The fix is to use the C++11 thread-safe static local variable pattern, which is both simpler and guaranteed to be thread-safe by the standard.

```diff
--- a/services/media_mtp/src/mtp_storage_manager.cpp
+++ b/services/media_mtp/src/mtp_storage_manager.cpp
@@ -45,15 +45,9 @@

 namespace OHOS {
 namespace Media {
-std::shared_ptr<MtpStorageManager> MtpStorageManager::instance_ = nullptr;-std::mutex MtpStorageManager::mutex_;
-
 std::shared_ptr<MtpStorageManager> MtpStorageManager::GetInstance()
 {
-    if (instance_ == nullptr) {
-        std::lock_guard<std::mutex> lock(mutex_);
-        if (instance_ == nullptr) {
-            instance_ = std::make_shared<MtpStorageManager>();
-        }
-    }
-    return instance_;
+    static MtpStorageManager instance;
+    return std::shared_ptr<MtpStorageManager>(&instance, [](MtpStorageManager*) {});
 }
+
 } // namespace Media
```

